/**
 * Risk patterns for scanning issue/PR/comment text.
 * Each rule has: severity (0-100), category, regex, and a human-readable message.
 * Derived from Orbit's household scam scanner (src/agent/scam.js).
 */

const RISK_PATTERNS = [
  {
    severity: 100,
    category: "secret_request",
    pattern: /\b(seed phrase|private key|recovery phrase|mnemonic|wallet backup)\b/i,
    message: "Requests or mentions wallet secrets."
  },
  {
    severity: 95,
    category: "drain_phrase",
    pattern: /\b(unlimited approval|setapprovalforall|permit signature|increase allowance|approve all|token approval)\b/i,
    message: "Mentions high-risk approval behavior."
  },
  {
    severity: 90,
    category: "fund_transfer",
    pattern: /\b(send|transfer|bridge|swap)\b.{0,80}\b(eth|weth|usdc|token|treasury|funds?)\b/i,
    message: "Requests movement of funds or tokens."
  },
  {
    severity: 88,
    category: "fake_support",
    pattern: /\b(support agent|wallet support|sync your wallet|validate your wallet|rectify your wallet|fix your wallet)\b/i,
    message: "Uses common fake wallet-support language."
  },
  {
    severity: 86,
    category: "urgent_pressure",
    pattern: /\b(urgent|immediately|within \d+ minutes|final warning|last chance|your funds are at risk)\b/i,
    message: "Applies urgency pressure."
  },
  {
    severity: 84,
    category: "reward_claim",
    pattern: /\b(claim|airdrop|free token|reward|allocation)\b.{0,80}\b(connect|sign|approve|wallet)\b/i,
    message: "Combines rewards with wallet signing."
  },
  {
    severity: 80,
    category: "prompt_injection",
    pattern: /\b(ignore previous|ignore all|system prompt|developer message|you are now|jailbreak|disable safety)\b/i,
    message: "Attempts prompt or policy override."
  },
  {
    severity: 82,
    category: "encoded_instruction_relay",
    pattern: /\b(decode|decrypt|translate|convert|read)\b.{0,80}\b(morse|base64|hex|rot13|cipher|encoded)\b|\b(morse|base64|hex|rot13|cipher|encoded)\b.{0,80}\b(paste|post|reply|comment|send|say|plain ?text|plaintext|what (?:does|is)|means?)\b|\bwhat\s+(?:does|is)\b.{0,80}\b(morse|base64|hex|rot13|cipher|encoded)\b.{0,80}\b(say|mean|plain ?text|plaintext)\b/i,
    message: "Asks to decode or relay hidden visitor content."
  },
  {
    severity: 78,
    category: "obfuscation",
    pattern: /\b(base64|hex encoded|morse code|decode this|decrypt this|eval\(|atob\(|fromcharcode)\b/i,
    message: "Mentions encoded or executable payloads."
  },
  {
    severity: 74,
    category: "external_wallet",
    pattern: /\b0x[a-fA-F0-9]{40}\b/,
    message: "Contains an EVM address that may be an external recipient."
  },
  {
    severity: 75,
    category: "credential_phish",
    pattern: /\b(?:api key|password|login token|github token|secret)\b.{0,80}\b(?:send|share|paste|post|enter)\b|\b(?:send|share|paste|post|enter)\b.{0,80}\b(?:api key|password|login token|github token|secret)\b/i,
    message: "Requests credential sharing."
  }
];

const SHORTENER_DOMAINS = new Set([
  "bit.ly",
  "tinyurl.com",
  "t.co",
  "rebrand.ly",
  "cutt.ly",
  "is.gd",
  "buff.ly",
  "ow.ly"
]);

const SAFE_DOMAINS = new Set([
  "github.com",
  "docs.github.com",
  "gitlab.com",
  "stackoverflow.com",
  "developer.mozilla.org",
  "npmjs.com"
]);

module.exports = { RISK_PATTERNS, SHORTENER_DOMAINS, SAFE_DOMAINS };

"use strict";

const { RISK_PATTERNS, SHORTENER_DOMAINS, SAFE_DOMAINS } = require("./rules");

/**
 * Extract all http(s) URLs from text.
 */
function extractUrls(text) {
  return Array.from(String(text || "").matchAll(/\bhttps?:\/\/[^\s<>"')]+/gi)).map((m) => m[0]);
}

/**
 * Get the domain from a URL string.
 */
function domainOf(url) {
  try {
    return new URL(url).hostname.toLowerCase().replace(/^www\./, "");
  } catch {
    return "";
  }
}

/**
 * Scan a single URL for risk signals.
 */
function scanUrl(url) {
  const domain = domainOf(url);
  const flags = [];

  if (!domain) {
    flags.push({ severity: 50, category: "malformed_url", message: "URL could not be parsed.", url });
  } else if (SHORTENER_DOMAINS.has(domain)) {
    flags.push({ severity: 80, category: "shortened_url", message: "Shortened links hide the final destination.", url, domain });
  } else if (!SAFE_DOMAINS.has(domain) && /wallet|claim|airdrop|reward|token|swap|bridge|approve/i.test(url)) {
    flags.push({ severity: 70, category: "unknown_financial_domain", message: "Unknown financial or wallet-related domain.", url, domain });
  }

  if (/[^\x20-\x7e]/.test(url)) {
    flags.push({ severity: 65, category: "unicode_url", message: "URL contains non-ASCII characters.", url, domain });
  }

  return flags;
}

/**
 * Map a numeric severity score to a human-readable risk level.
 */
function riskLevel(score) {
  if (score >= 90) return "critical";
  if (score >= 70) return "high";
  if (score >= 40) return "medium";
  if (score > 0) return "low";
  return "clear";
}

/**
 * Scan text for all risk patterns and URL risks.
 * Returns { safe, level, score, flags }.
 */
function scanText(text) {
  const value = String(text || "");
  const flags = [];

  for (const rule of RISK_PATTERNS) {
    if (rule.pattern.test(value)) {
      flags.push({
        severity: rule.severity,
        category: rule.category,
        message: rule.message
      });
    }
  }

  for (const url of extractUrls(value)) {
    flags.push(...scanUrl(url));
  }

  const score = flags.reduce((max, f) => Math.max(max, f.severity), 0);
  return {
    safe: score < 70,
    level: riskLevel(score),
    score,
    flags
  };
}

/**
 * Scan a GitHub issue/PR event payload.
 * Accepts { title, body, user, labels, comments[] }.
 * Returns { safe, level, score, flags, parts }.
 */
function scanEvent(event = {}) {
  const parts = {};

  if (event.title) parts.title = scanText(event.title);
  if (event.body) parts.body = scanText(event.body);

  if (Array.isArray(event.comments)) {
    parts.comments = event.comments.map((c, i) => ({
      index: i,
      user: c.user || null,
      ...(c.body ? scanText(c.body) : { safe: true, level: "clear", score: 0, flags: [] })
    }));
  }

  const allScores = [
    parts.title?.score || 0,
    parts.body?.score || 0,
    ...(parts.comments || []).map((c) => c.score || 0)
  ];
  const score = Math.max(...allScores);

  return {
    safe: score < 70,
    level: riskLevel(score),
    score,
    flags: [
      ...(parts.title?.flags || []),
      ...(parts.body?.flags || []),
      ...((parts.comments || []).flatMap((c) => c.flags || []))
    ],
    parts
  };
}

/**
 * Format a scan result as a short summary string.
 */
function formatSummary(result, label = "") {
  const prefix = label ? `[${label}] ` : "";
  if (result.safe) {
    return `${prefix}Clear — no risk flags detected.`;
  }
  const categories = [...new Set(result.flags.map((f) => f.category))];
  return `${prefix}${result.level.toUpperCase()} (score ${result.score}) — flagged: ${categories.join(", ")}`;
}

module.exports = {
  extractUrls,
  domainOf,
  scanUrl,
  scanText,
  scanEvent,
  formatSummary,
  riskLevel
};

